import sys

class Solution:
  def minPriorityQueue(self, arr, n):
    for i in range(n // 2 - 1, -1, -1):
      self.heapify(arr, n, i)
    min = float('inf')
    for i in range(n):
      min = min if min < arr[i] else arr[i]
    return min

def heapify(self, arr, n, i):
  smallest = i
  if 2 * i + 1 < n and arr[2 * i + 1] < arr[smallest]:
    smallest = 2 * i + 1
  if 2 * i + 2 < n and arr[2 * i + 2] < arr[smallest]:
    smallest = 2 * i + 2
  if smallest != i:
    arr[i] += arr[smallest]
    arr[smallest] = arr[i] - arr[smallest]
    arr[i] -= arr[smallest]
    self.heapify(arr, n, smallest)

