#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

class Solution {
public:
  void heapify(vector<int>& arr, int n, int i){
    int smallest = i;
    if (2 * i + 1 < n && arr[2 * i + 1] < arr[smallest]) smallest = 2 * i + 1;
    if (2 * i + 2 < n && arr[2 * i + 2] < arr[smallest]) smallest = 2 * i + 2;
    if (smallest != i){
      arr[i] += arr[smallest];
      arr[smallest] = arr[i] - arr[smallest];
      arr[i] -= arr[smallest];
      heapify(arr, n, smallest);
    }
  }

  int minPriorityQueue(vector<int>& arr, int n){
    for (int i = n / 2 - 1; i >= 0; i--) heapify(arr, n, i);
    int min = INT_MAX;
    for (int i = 0; i < n; i++) min = std::min(min, arr[i]);
    return min;
  }

  void solve(){
    int n;
    cin >> n;
    vector<int> arr(n);
    for (int i = 0; i < n; i++) cin >> arr[i];
    cout << minPriorityQueue(arr, n) << endl;
  }

